INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(2, 1, '03', 'CPI 개념', '소비자물가지수(CPI)에 대한 설명으로 가장 적절한 것은?', '기업 생산원가만 측정한다', '소비자 구매 바구니의 가격 변화를 측정한다', '환율 변동만 반영한다', '실업률 대체 지표다', 1, '문서에서 CPI는 소비자가 실제 구매하는 상품·서비스 바구니 가격 변화를 측정하는 지표로 설명됩니다.'),
(2, 2, '03', 'Core CPI', '문서에서 핵심 근원물가(Core CPI)는 무엇을 제외한 지표인가?', '주거비와 의료비', '교통비와 교육비', '에너지와 식품', '수입품과 수출품', 2, 'Core CPI는 에너지·식품을 제외해 변동성을 줄이고 추세 파악에 유리하다고 설명합니다.'),
(2, 3, '03', 'PPI 특징', '생산자물가지수(PPI)의 활용으로 옳은 것은?', '소비자 심리만 측정한다', 'CPI보다 선행성이 있어 미래 물가 예측에 활용된다', '금리결정과 무관하다', '주식 변동성만 설명한다', 1, '문서에서 PPI는 CPI보다 선행성이 있어 미래 물가 예측에 사용된다고 제시합니다.'),
(2, 4, '03', '물가 파급 경로', '문서의 PPI→CPI 파급 경로에 포함되는 단계는?', '원자재 가격 상승 → 기업 원가 상승 → 제품 가격 전가', '실업률 하락 → 임금 하락 → CPI 하락', '환율 하락 → 수입 감소 → PPI 하락', '세수 증가 → 기준금리 인상 → CPI 상승', 0, '문서의 도식은 원자재·에너지 가격 상승이 PPI, 기업 원가, 제품 가격 전가를 거쳐 CPI로 이어지는 흐름을 설명합니다.'),
(2, 5, '03', 'WTI 시장', 'WTI 원유의 기준 시장으로 문서에 제시된 것은?', 'ICE(런던)', 'NYMEX(뉴욕)', 'KRX(서울)', 'LME(런던금속거래소)', 1, 'WTI는 문서에서 NYMEX(뉴욕) 기준 원유로 설명됩니다.'),
(2, 6, '03', '브렌트유 특징', '브렌트유에 대한 설명으로 옳은 것은?', '미국 내수 전용 기준 유종이다', '항상 WTI보다 저렴하다', '글로벌 기준 원유로 세계 원유 가격의 주요 벤치마크다', '천연가스 가격 지표다', 2, '문서에서는 브렌트유를 글로벌 기준 원유(세계 원유 70%+ 기준)로 설명합니다.'),
(2, 7, '03', '유가 상승 영향', '유가 상승 시 상대적으로 피해가 커질 수 있는 업종으로 제시된 것은?', '정유', '에너지', '유전서비스', '항공', 3, '문서의 산업별 영향 표에서 유가 상승 시 항공·해운·원료 의존 화학 업종이 피해 업종으로 제시됩니다.'),
(2, 8, '03', '유가와 물가', '문서 기준 유가 상승의 거시경제 파급으로 가장 적절한 것은?', '에너지 비용 감소', '기업 원가 하락', '물가(CPI) 상승 압력', '환율 변동 없음', 2, '유가 상승은 에너지 비용과 기업 원가를 높여 CPI 상승 압력을 키운다고 설명합니다.'),
(2, 9, '03', '원화 약세', '원화 약세(환율 상승) 시 문서에서 제시된 효과는?', '수출기업 가격 경쟁력 상승', '수입 물가 하락', '외국인 자금 유입 가속', '코스피 상승 압력 고정', 0, '문서에서는 원화 약세 시 수출기업 가격 경쟁력 상승 효과를 제시합니다.'),
(2, 10, '03', '원화 약세 부작용', '원화 약세(환율 상승)의 부정적 파급으로 제시된 것은?', '수입 물가 하락', 'CPI 안정', '수입 물가 상승', '외화 조달 비용 감소', 2, '문서 도식에서 환율 상승은 수입 물가 상승으로 이어져 물가 압력을 키운다고 설명합니다.'),
(2, 11, '03', '원화 강세', '원화 강세(환율 하락) 시 문서에서 기대되는 흐름은?', '외국인 자금 유출 압력', '외국인 자금 유입 용이', '수입 물가 상승', '코스피 하락 압력 고정', 1, '문서에서는 원화 강세 시 외국인 자금 유입이 상대적으로 용이해질 수 있다고 설명합니다.'),
(2, 12, '03', '환율 의미', '원/달러 환율이 1,350원이라는 의미로 맞는 것은?', '원화 1개로 달러 1,350개를 산다', '달러 1개를 사려면 1,350원이 필요하다', '달러 가치가 1,350% 상승했다', '한국 기준금리가 1,350bp다', 1, '문서의 환율 기본 개념 설명에 따르면 원/달러 1,350원은 달러 1개를 사기 위해 1,350원이 필요하다는 뜻입니다.'),
(2, 13, '03', '환율-주가 상관', '문서의 환율·코스피 예시에서 일반적으로 관찰되는 경향은?', '환율 상승과 코스피 상승의 강한 양의 상관', '환율 상승과 코스피 하락 경향(음의 상관)', '항상 상관계수 0', '상관관계 계산 불가', 1, '문서의 코드 예시에 환율 상승 시 코스피 하락 경향(음수 상관) 해석이 명시되어 있습니다.'),
(2, 14, '03', 'GDP 성장률', '문서의 GDP 성장률 계산식으로 옳은 것은?', '(금기 GDP - 전기 GDP) / 전기 GDP × 100', '(금기 GDP - 전기 GDP) / 금기 GDP × 100', '(전기 GDP - 금기 GDP) / 전기 GDP × 100', '금기 GDP / 인구수 × 100', 0, '문서에 GDP 성장률은 (금기 GDP - 전기 GDP) / 전기 GDP × 100으로 제시됩니다.'),
(2, 15, '03', '기술적 경기침체', '문서에서 기술적 경기침체 신호로 제시된 조건은?', 'GDP 성장률 2% 이상 2분기 연속', '실업률 2% 이하', 'GDP가 2분기 연속 마이너스', 'CPI가 2개월 연속 하락', 2, '문서의 GDP 성장률 구간별 신호에서 2분기 연속 마이너스를 기술적 경기침체로 설명합니다.'),
(2, 16, '03', '실업률 정의', '문서 기준 실업률의 정의로 옳은 것은?', '전체 인구 중 취업자의 비율', '경제활동인구 중 일할 의사가 있으나 직업이 없는 사람의 비율', '청년 인구 중 대학 진학자의 비율', '기업 수 대비 폐업 기업 비율', 1, '문서에서는 실업률을 경제활동인구 중 일할 의사가 있으나 직업이 없는 사람의 비율로 설명합니다.'),
(2, 17, '03', '고용지표 발표', '문서 기준 미국 비농업 고용(NFP) 발표 시점은?', '매월 첫째 월요일', '매월 셋째 수요일', '매월 첫째 금요일', '분기 마지막 영업일', 2, '문서 표에 NFP는 매월 첫째 금요일 발표로 제시됩니다.'),
(2, 18, '03', 'ADP 발표 시점', 'ADP 민간 고용은 문서에서 NFP 대비 언제 발표된다고 설명하는가?', 'NFP와 동일 시각', 'NFP 발표 2일 전 수요일', 'NFP 발표 다음 주 월요일', '분기말에만 발표', 1, '문서의 발표 순서 도식에서 ADP는 NFP 발표 2일 전 수요일의 선행 지표로 설명됩니다.'),
(2, 19, '03', '프록시 지표', '문서의 Python 소스 연계에서 GDP·실업률 프록시로 함께 조회하는 지표는?', '^TNX와 ^FVX', 'CL=F와 GC=F', 'KRW=X와 ^KS11', 'CPIAUCSL와 PPIACO', 0, '문서는 yfinance로 GDP·실업률 직접 수집이 어려워 ^TNX, ^FVX 같은 금리 지표를 프록시로 활용한다고 설명합니다.'),
(2, 20, '03', '티커 식별', '문서에서 USD/KRW 환율 yfinance 티커는?', 'USDKRW', 'KRWUSD=X', 'KRW=X', '^KRW', 2, '문서 예시 코드에서 원/달러 환율은 KRW=X로 조회합니다.'),
(2, 21, '03', '티커 식별 2', '문서에서 WTI 선물 가격 조회 티커는?', 'WTI', 'CL=F', 'BRN=F', '^OIL', 1, '문서의 코드에서 WTI 원유 선물은 CL=F로 수집합니다.'),
(2, 22, '03', '달러인덱스', '문서의 yfinance 예시에서 달러인덱스 티커는?', 'DXY', 'DX-Y.NYB', 'USDX=F', '^DOLLAR', 1, '문서의 MARKET_TICKERS 예시에서 달러인덱스는 DX-Y.NYB로 정의되어 있습니다.'),
(2, 23, '03', '데이터 해석 주의', '문서에서 ^TNX 사용 시 주의사항으로 제시된 것은?', '분기 데이터라 월별 변환 불가', '실업률만 반영하므로 금리 해석 불가', 'Yahoo 표기 스케일(10배처럼 보이는 값) 확인 필요', '항상 결측치가 50% 이상 발생', 2, '문서는 ^TNX가 Yahoo 표기상 10배 조정된 수익률처럼 보일 수 있어 단위·스케일 확인을 권고합니다.'),
(2, 24, '03', '빈도 통일', '문서에서 상관관계 분석 시 권장하는 빈도 정렬 방식은?', '모든 지표를 일별로 강제 보간', '월말 또는 월평균 기준으로 빈도를 맞춘다', '분기 지표는 제거한다', '원천 주기를 그대로 유지한다', 1, '문서에서는 일별 시장데이터와 월별/분기별 거시지표를 월말/월평균 기준으로 통일하라고 안내합니다.'),
(2, 25, '03', '변환 방식', '문서의 변환 선택 원칙에서 CPI/PPI에 권장된 방식은?', '로그레벨 고정', '절대값 차분만 사용', 'YoY 또는 MoM', '누적합', 2, '문서의 표에서 CPI, PPI는 추세 변화를 위해 YoY 또는 MoM 변환을 권장합니다.'),
(2, 26, '03', '상관 해석', '문서의 상관관계 해석 원칙으로 옳은 것은?', '상관계수는 인과관계를 증명한다', '상관관계가 0이면 데이터 오류다', '상관관계는 인과관계가 아니다', '상관계수는 경제 데이터에 사용할 수 없다', 2, '문서에 상관관계는 인과관계가 아니라는 주의 문구가 명시되어 있습니다.'),
(2, 27, '03', '롤링 상관', '12개월 롤링 상관관계를 사용하는 주된 이유는?', '결측치를 자동 제거하기 위해', '국면 변화에 따른 관계 강도 변화를 확인하기 위해', '상관계수를 항상 0으로 만들기 위해', '분기 데이터를 일별로 변환하기 위해', 1, '문서에서는 전체 기간 단일 상관계수만으로는 국면 변화를 놓치므로 12개월 롤링 상관을 사용한다고 설명합니다.'),
(2, 28, '03', '시차 상관', '문서의 시차 상관 해석에서 lag_months > 0 이고 상관이 높을 때의 의미는?', 'y가 항상 x를 선행한다', 'x가 먼저 움직이고 y가 뒤따를 가능성을 검토한다', '두 지표가 무관함을 확정한다', '통계 검정이 불필요하다', 1, '문서는 lag_months > 0 구간에서 상관이 높으면 x 선행 가능성을 검토하되 통계적 검정과 경제적 해석을 함께 하라고 안내합니다.'),
(2, 29, '03', '표준 스키마', '문서의 표준 데이터 스키마에서 분석용 변환 방식을 나타내는 컬럼은?', 'series_name', 'unit', 'transform', 'frequency', 2, '표준 스키마 표에서 transform 컬럼은 level/return/yoy 같은 분석 변환 방식을 의미합니다.'),
(2, 30, '03', 'API 키 전략', '문서의 실습 전략으로 옳은 것은?', '모든 API 키 없이는 실습 시작 불가', '먼저 yfinance로 시작하고 공식 API를 단계적으로 붙인다', 'BLS만 쓰고 다른 출처는 금지한다', '키 발급 전에는 데이터 분석을 하지 않는다', 1, '문서는 yfinance로 빠르게 시작한 뒤 FRED/BLS/BEA/EIA/ECOS 등을 단계적으로 연동하라고 권장합니다.');
